rotater &lt;- function(my_way, dd, nn) {
  if (dd == "L") {
    if (nn == "90") {
      qq = "L"
    } else if (nn == "180") {
      qq = "S"
    } else if (nn == "270") {
      qq = "R"
    } else {
      print("oops")
    }
  } else if (dd == "R") {
    if (nn == "90") {
      qq = "R"
    } else if (nn == "180") {
      qq = "S"
    } else if (nn == "270") {
      qq = "L"
    } else {
      print("oops")
    }
  }
  new_way &lt;- my_way
  if (qq == "L") {
    my_way$y = new_way$x
    my_way$x = new_way$y * -1
  } else if (qq == "R") {
    my_way$y = new_way$x * -1
    my_way$x = new_way$y  
  } else if (qq == "S") {
    temp = my_way$y
    my_way$x = new_way$x * -1 
    my_way$y = new_way$y  * -1
  } else {
    print("oops")
  }
  return(my_way)  
}

