def treeview(x, y):
    t = tre[x,y]
    u = 0
    d = 0
    l = 0
    r = 0
    # up
    if x == 1: 
        u = 1
    else: 
        for i in range(x-1, -1, -1):
            if t &gt; tre[i, y]:
                u += 1
            if t &lt;= tre[i, y]:
                u += 1
                break
    # down
    if x == 97:
        d = 1
